#ifndef _SOFA_PBRPC_SMART_PTR_DETAIL_SPINLOCK_PT_
#define _SOFA_PBRPC_SMART_PTR_DETAIL_SPINLOCK_PT_

#include <pthread.h>

namespace sofa {
namespace pbrpc {
namespace detail {

class spinlock
{
public:

    pthread_mutex_t v_;

public:

    bool try_lock()
    {
        return pthread_mutex_trylock( &v_ ) == 0;
    }

    void lock()
    {
        pthread_mutex_lock( &v_ );
    }

    void unlock()
    {
        pthread_mutex_unlock( &v_ );
    }

public:

    class scoped_lock
    {
    private:

        spinlock & sp_;

        scoped_lock( scoped_lock const & );
        scoped_lock & operator=( scoped_lock const & );

    public:

        explicit scoped_lock( spinlock & sp ): sp_( sp )
        {
            sp.lock();
        }

        ~scoped_lock()
        {
            sp_.unlock();
        }
    };
};

} // namespace detail
} // namespace pbrpc
} // namespace sofa

#define SOFA_PBRPC_SMART_PTR_DETAIL_SPINLOCK_INIT { PTHREAD_MUTEX_INITIALIZER }

#endif // _SOFA_PBRPC_SMART_PTR_DETAIL_SPINLOCK_PT_

